#include <bits/stdc++.h>
using namespace std;
const int N=600005;
int a[N],n,t,s[N][20];
long long ans,f[N],f2[N];
unordered_map<int,vector<int> > m;
unordered_map<int,int> l;
int query(int l,int r)
{
	int t=log2(r-l+1);
	return max(s[l][t],s[r-(1<<t)+1][t]);
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        a[i]=abs(a[i]);
        m[a[i]].push_back(i);
    }
	for(int i=2;i<=n;i++) f2[i]=f2[i-1]+i-1;
    for(int j=0;j<20;j++)
    {
        for(int i=1;i+(1<<j)-1<=n;i++)
        {
            if(!j) s[i][j]=a[i];
            else s[i][j]=max(s[i][j-1],s[i+(1<<j-1)][j-1]);
        }
    }
    for(int i=3;i<=n;i++)
    {
		if(i&1) t++;
		f[i]=f[i-1]+t;
	}
	for(int i=1;i<=n;i++)
    {
		int cnt=0,j=l[a[i]];
		for(;j<m[a[i]].size();j++)
        {
			if(query(i,m[a[i]][j])>a[i]) break;
			else cnt++;
		}
		l[a[i]]=j;
		if(a[i]!=0) ans+=f[cnt];
        else ans+=f2[cnt];
	}
	cout<<ans;
    return 0;
}
